function handleGlobalKeydown(event) {
  const target = event.target;
  const isTyping = target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement || target instanceof HTMLSelectElement || target?.isContentEditable;
  if (event.key === "Escape") {
    if (state.modal || state.moreOpen || state.mapMenuOpen) {
      state.modal = null;
      state.editId = null;
      state.moreOpen = false;
      state.mapMenuOpen = false;
      state.pictureTarget = "";
      state.templateServiceId = "";
      render();
    }
    return;
  }
  if (event.key === "/" && !isTyping) {
    event.preventDefault();
    state.view = "search";
    render();
    requestAnimationFrame(() => document.querySelector("#pageSearchInput,#searchInput")?.focus());
  }
}

document.addEventListener("keydown", handleGlobalKeydown);

let resizeRefreshTimer = null;
if (typeof window !== "undefined") {
  window.addEventListener("resize", () => {
    clearTimeout(resizeRefreshTimer);
    resizeRefreshTimer = setTimeout(() => render(), 160);
  });

  if ("serviceWorker" in navigator && window.location.protocol.startsWith("http")) {
    window.addEventListener("load", () => {
      navigator.serviceWorker.register("./sw.js").catch(() => {});
    });
  }
}

render();
setTimeout(() => { void attemptIndexedRecovery(); }, 80);
